// Use Code node to make HTTP request with proper JSON
const items = $input.all();

// Prepare the request payload
const payload = {
  content_id: `test_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
  domain: 'finance',
  prompt: 'Write a comprehensive analysis of current market trends and their implications for investors.',
  style_parameters: {
    tone: 'professional',
    complexity: 'intermediate',
    structure: 'analysis',
    length: 'medium',
    perspective: 'third-person'
  },
  source_metadata: {
    title: 'Market Trends Analysis Test',
    description: 'Testing content generation with comprehensive market data',
    url: 'https://example.com/market-trends',
    pub_date: new Date().toISOString()
  }
};

console.log('Preparing to call content generation API with payload:', JSON.stringify(payload, null, 2));

// Make HTTP request using fetch
try {
  const response = await fetch('http://localhost:8010/api/v1/content/generate', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Request-ID': payload.content_id
    },
    body: JSON.stringify(payload)
  });

  console.log(`API Response Status: ${response.status}`);

  if (response.ok) {
    const result = await response.json();
    console.log('Content generation successful:', result.content_id);

    return [{
      json: {
        success: true,
        api_response: result,
        request_payload: payload,
        status: response.status,
        timestamp: new Date().toISOString()
      }
    }];
  } else {
    const errorText = await response.text();
    console.error(`API Error ${response.status}:`, errorText);

    return [{
      json: {
        success: false,
        error: `HTTP ${response.status}`,
        error_details: errorText,
        request_payload: payload,
        timestamp: new Date().toISOString()
      }
    }];
  }
} catch (error) {
  console.error('Request failed:', error.message);

  return [{
    json: {
      success: false,
      error: 'Request failed',
      error_details: error.message,
      request_payload: payload,
      timestamp: new Date().toISOString()
    }
  }];
}
